import { AttachInternals, Component, Element, Event, EventEmitter, h, Listen, Prop, State, Watch } from '@stencil/core';
import { generateRandId, twMerge } from '../../utils/utils';
import { formatDateToString, isAfterDay, isBeforeDay, isValidDateString, parseDateFromString } from '../../utils/date.utils';
import { CalendarSize, CalendarVariant } from '../wdpr-calendar/wdpr-calendar.model';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { wrapperTextFieldClasses } from '../wdpr-datepicker/wdpr-datepicker.model';

@Component({
  tag: 'wdpr-range-datepicker',
  shadow: true,
  formAssociated: true,
})
export class WdprRangeDatePicker {
  /**
   * @internal Reference to wdpr-range-datepicker-input component.
   */
  private _dualTextFieldElement: HTMLWdprDualTextFieldElement;

  /**
   * @internal Reference to wdpr-calendar component.
   */
  private _calendarElement: HTMLWdprCalendarElement;

  /**
   * Reference to host element
   * @type {HTMLWdprRangeDatepickerElement}
   */
  @Element() el: HTMLWdprRangeDatepickerElement;
  @AttachInternals() internals: ElementInternals;

  /**
   * The flag that expand or not the calendar.
   * @type {boolean}
   */
  @State() _expanded: boolean = false;

  /**
   * @internal
   * Tracks which field (start/end) the user last clicked to open the calendar.
   * Used to inform the calendar which date endpoint to update on the first selection.
   */
  @State() _activeField: 'start' | 'end' = 'start';

  /**
   * @internal
   * The internal ID for the dialog. It is used internally and is not exposed.
   */
  @State() _internalDialogId: string;

  /**
   * The disabled state.
   * @type {string}
   */
  @Prop() disabled: boolean = false;

  /**
   * Flag that enables or not an extra week.
   * @type {boolean}
   */
  @Prop() enableSixWeeks: boolean = false;

  /**
   * The start label for the input.
   * @type {string}
   */
  @Prop() startLabel: string = 'Start Label';

  /**
   * The end label for the input.
   * @type {string}
   */
  @Prop() endLabel: string = 'End Label';

  /**
   * The date format string (uses date-fns format syntax).
   *
   * @default "MM/dd/yyyy"
   * @example "dd-MM-yyyy"
   * @type {string}
   */
  @Prop() format: string = 'MM/dd/yyyy';

  /**
   * Default start date for range selection .
   * Must follow the format specified in the `format` prop.
   *
   * @example "06/10/2025"
   * @type {string}
   */
  @Prop({ mutable: true, reflect: true }) start?: string;

  /**
   * Default end date for range selection.
   * Must follow the format specified in the `format` prop.
   *
   * @example "06/20/2025"
   * @type {string}
   */
  @Prop({ mutable: true, reflect: true }) end?: string;

  /**
   * Name for the start date in form submission.
   */
  @Prop() startName?: string;

  /**
   * Name for the end date in form submission.
   */
  @Prop() endName?: string;

  /**
   * Min date for the calendar to show.
   * Must follow the format specified in the `format` prop.
   *
   * @example "06/10/2025"
   * @type {string}
   */
  @Prop({ mutable: true, reflect: true }) min?: string = formatDateToString(new Date(0, 0, 1), this.format);

  /**
   * Max date the calendar to show.
   * Must follow the format specified in the `format` prop.
   *
   * @example "06/20/2025"
   * @type {string}
   */
  @Prop({ mutable: true, reflect: true }) max?: string;

  /**
   * Error state of the text field
   * @type {boolean}
   */
  @Prop() error: boolean = false;

  /**
   * The calendar display variant.
   * - `single`: one month view
   * - `double`: two months side by side
   * - `swipe`: swipe between months
   *
   * @default "single"
   * @type {"single" | "double" | "swipe"}
   */
  @Prop() variant: CalendarVariant = 'single';

  /**
   * Helper text for the wdpr-text-field. Could be for error or just info.
   * @type {string}
   */
  @Prop() helperText: string;

  /**
   * (Optional) A unique ID for the component. It is essential for accessibility,
   * If not provided, a random ID will be generated.
   * @type {string}
   */
  @Prop() dialogId?: string;

  /**
   * Flag that shows or hide the calendar borders
   * @default true
   * @type {boolean}
   */
  @Prop() displayCalendarBorder: boolean = true;

  /**
   * Flag that shows or hide the calendar box shadow
   * @default true
   * @type {boolean}
   */
  @Prop() showBoxShadow: boolean = true;
  /**
   * Readonly state of the text field
   * @type {boolean}
   */
  @Prop() readonly: boolean = false;

  @Prop() calendarSize: CalendarSize = 'medium';

  @Prop() inputMaxWidth: boolean = false;

  /**
   * Fired when a valid range of dates is selected.
   * @event rangeDatesSelected
   * @type {CustomEvent<{ startDate?: string; endDate?: string }>}
   * @property {string} [startDate] - Start date as an ISO string (e.g. "2025-06-19").
   * @property {string} [endDate] - End date as an ISO string (e.g. "2025-06-25").
   */
  @Event() rangeDatesSelected: EventEmitter<{ startDate?: string; endDate?: string }>;

  /**
   * Fired when an invalid date input is detected (wrong format, out of range, or invalid range).
   * @event dateInvalid
   * @type {CustomEvent<{ type: 'invalid-format' | 'out-of-range' | 'invalid-range'; start?: string; end?: string }>}
   * @property {'invalid-format' | 'out-of-range' | 'invalid-range'} type - Type of invalidity.
   * @property {string} [start] - Start date as an ISO string (if provided).
   * @property {string} [end] - End date as an ISO string (if provided).
   */
  @Event() dateInvalid: EventEmitter<{ type: 'invalid-format' | 'out-of-range' | 'invalid-range'; start?: string; end?: string }>;

  @Listen('click', { target: 'document' })
  handleClickOutside(event: MouseEvent) {
    if (this._expanded && this.el && !event.composedPath().includes(this.el)) {
      this._expanded = false;
    }
  }

  componentWillLoad() {
    this._internalDialogId = this.dialogId || `wdpr-range-datepicker-calendar-${generateRandId()}`;
    this._updateFormValue();
  }

  componentDidLoad() {
    const extras = this._getDateExtras();
    this._calendarElement.setExtras(extras);
  }

  @Watch('start')
  @Watch('end')
  @Watch('disabled')
  @Watch('startName')
  @Watch('endName')
  handleFormPropsChanged() {
    this._updateFormValue();
  }

  private _toggleExpandCalendar = () => {
    if (!this.disabled) {
      this._expanded = !this._expanded;
    }
  };

  private handleRangeDatesSelected = async (event: CustomEvent<{ startDate?: string; endDate?: string }>) => {
    const { startDate, endDate } = event.detail;

    event.stopPropagation();

    this.start = startDate;
    this.end = endDate;

    if (endDate) {
      this._expanded = false;
      this._activeField = 'start';
      await this._dualTextFieldElement.setTrailingFocus();
    }

    this.rangeDatesSelected.emit({ startDate: this.start, endDate: this.end });
  };

  private _handleRangeDatesChanged = (event: CustomEvent<{ leadingValue?: string; trailingValue?: string }>) => {
    const { leadingValue: startDate, trailingValue: endDate } = event.detail;

    if (startDate && !isValidDateString(startDate, this.format)) {
      this.dateInvalid.emit({ type: 'invalid-format', start: startDate });

      return;
    }

    if (endDate && !isValidDateString(endDate, this.format)) {
      this.dateInvalid.emit({ type: 'invalid-format', end: endDate });

      return;
    }

    const parsedStart = startDate ? parseDateFromString(startDate, this.format) : undefined;
    const parsedEnd = endDate ? parseDateFromString(endDate, this.format) : undefined;
    const parsedMin = this.min ? parseDateFromString(this.min, this.format) : undefined;
    const parsedMax = this.max ? parseDateFromString(this.max, this.format) : undefined;

    if (parsedStart && ((parsedMin && isBeforeDay(parsedStart, parsedMin)) || (parsedMax && isAfterDay(parsedStart, parsedMax)))) {
      this.dateInvalid.emit({ type: 'out-of-range', start: startDate });

      return;
    }

    if (parsedEnd && ((parsedMin && isBeforeDay(parsedEnd, parsedMin)) || (parsedMax && isAfterDay(parsedEnd, parsedMax)))) {
      this.dateInvalid.emit({ type: 'out-of-range', end: endDate });

      return;
    }

    if (parsedStart && parsedEnd && isAfterDay(parsedStart, parsedEnd)) {
      this.dateInvalid.emit({
        type: 'invalid-range',
        start: startDate,
        end: endDate,
      });

      return;
    }

    this.start = startDate;
    this.end = endDate;

    this.rangeDatesSelected.emit({ startDate: this.start, endDate: this.end });
  };

  private _handleInputClick = (event: CustomEvent<{ field: 'leading' | 'trailing' }>) => {
    if (this.readonly) return;

    this._activeField = event.detail?.field === 'trailing' ? 'end' : 'start';
    this._expanded = true;
  };

  private _handleInputKeyDown = async (ev: KeyboardEvent) => {
    if (this.readonly) return;

    if (ev.key === KEYBOARD_KEYS.ARROW_DOWN) {
      ev.preventDefault();
      this._expanded = true;

      await this._waitForNextRender();

      if (this._calendarElement) {
        const focusDate = this.start || this.min || this._getTodayString();
        this._calendarElement.setFocusDate(parseDateFromString(focusDate, this.format));
      }
    }

    if (ev.key === KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      this._expanded = false;
    }
  };

  private _handleCalendarKeyDown = async (ev: KeyboardEvent) => {
    if (ev.key === KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      this._expanded = false;
      await this._dualTextFieldElement.setLeadingFocus();
    }
  };

  private _waitForNextRender(): Promise<void> {
    return new Promise(resolve => requestAnimationFrame(() => resolve()));
  }

  private _getTodayString(): string {
    const today = new Date();

    return formatDateToString(today, this.format);
  }

  private _getDateExtras() {
    const slotNodes = this.el.querySelectorAll('[slot^="date-info-"]');
    const extras = new Map<string, HTMLElement>();

    slotNodes.forEach(node => {
      const dateKey = node.getAttribute('slot').replace('date-info-', '');
      if (dateKey) extras.set(dateKey, node as HTMLElement);
    });

    return extras;
  }

  private _updateFormValue() {
    const shouldSubmit = !this.disabled && !!this.startName && !!this.endName;

    if (!shouldSubmit) {
      this.internals?.setFormValue?.(null);
      this.internals?.setValidity?.({});

      return;
    }

    const formData = new FormData();
    formData.append(this.startName, this.start ?? '');
    formData.append(this.endName, this.end ?? '');
    this.internals?.setFormValue?.(formData);
    this.internals?.setValidity?.({});
  }

  private get _calendarWrapperClasses() {
    const baseClasses = 'absolute mt-100 left-1/2 -translate-x-1/2 translate-y-0 w-fit bg-surface-default rounded-150 z-10';
    const shadowClass = this.showBoxShadow ? 'p-200 border-solid border-012 border-stroke-neutral-light elevation-medium-soft' : '';
    const _expandedClasses = this._expanded && !this.disabled ? 'block' : 'hidden';

    return twMerge(baseClasses, shadowClass, _expandedClasses);
  }

  private get _textFieldWrapperClasses() {
    if (this.inputMaxWidth) return 'w-full';

    return twMerge('m-auto md:w-[358px]', wrapperTextFieldClasses[this.calendarSize]);
  }

  render() {
    return (
      <div class="relative">
        <div class={this._textFieldWrapperClasses}>
          <wdpr-dual-text-field
            ref={el => (this._dualTextFieldElement = el as HTMLWdprDualTextFieldElement)}
            leadingLabel={this.startLabel}
            trailingLabel={this.endLabel}
            leadingValue={this.start}
            trailingValue={this.end}
            error={this.error}
            disabled={this.disabled}
            helperText={this.helperText}
            readonly={this.readonly}
            a11yRole="combobox"
            a11yHasPopup="dialog"
            a11yControls={this._internalDialogId}
            a11yExpanded={this._expanded ? 'true' : 'false'}
            onWdprInputClick={this._handleInputClick}
            onWdprValueChanged={this._handleRangeDatesChanged}
            onKeyDown={this._handleInputKeyDown}
          >
            {!this.readonly && (
              <wdpr-icon-button
                size="medium"
                iconName="calendar-month"
                slot="trailing-icon-button"
                a11yLabel="Choose Dates"
                disabled={this.disabled}
                onClicked={this._toggleExpandCalendar}
                customTabIndex={-1}
              />
            )}
          </wdpr-dual-text-field>
        </div>

        <div id={this._internalDialogId} class={this._calendarWrapperClasses} part="calendar-wrapper" role="dialog" aria-label="Choose Date">
          <wdpr-calendar
            ref={el => (this._calendarElement = el as HTMLWdprCalendarElement)}
            mode="range"
            enableSixWeeks={this.enableSixWeeks}
            start={this.start}
            end={this.end}
            format={this.format}
            min={this.min}
            max={this.max}
            variant={this.variant}
            displayBorder={this.displayCalendarBorder}
            rangeActiveField={this._activeField}
            onRangeDatesSelected={this.handleRangeDatesSelected}
            onKeyDown={this._handleCalendarKeyDown}
            exportparts="calendar, calendar-surface"
            size={this.calendarSize}
          />
        </div>
      </div>
    );
  }
}
